class Solution:
    def mincostToHireWorkers(self, quality, wage, k):
        n = len(quality)
        best = float('inf')
        for captain in range(n):
            rate = wage[captain] / quality[captain]
            costs = []
            for i in range(n):
                if wage[i] / quality[i] <= rate + 1e-9:
                    costs.append(rate * quality[i])
            if len(costs) >= k:
                costs.sort()
                best = min(best, sum(costs[:k]))
        return best

