import heapq
class Solution:
    def mincostToHireWorkers(self, quality, wage, k):
        workers = sorted((wage[i] / quality[i], quality[i]) for i in range(len(quality)))
        heap = []
        q_sum = 0
        best = float('inf')
        for rate, q in workers:
            heapq.heappush(heap, -q)
            q_sum += q
            if len(heap) > k:
                q_sum += heapq.heappop(heap)
            if len(heap) == k:
                best = min(best, rate * q_sum)
        return best

