var mincostToHireWorkers = function(quality, wage, k) {
    const n = quality.length;
    const workers = [];
    for (let i = 0; i < n; i++) workers.push([wage[i] / quality[i], quality[i]]);
    workers.sort((a, b) => a[0] - b[0]);
    const heap = [];
    const heapPush = (val) => {
        heap.push(val);
        let i = heap.length - 1;
        while (i > 0) {
            const par = (i - 1) >> 1;
            if (heap[par] >= heap[i]) break;
            [heap[par], heap[i]] = [heap[i], heap[par]];
            i = par;
        }
    };
    const heapPop = () => {
        const top = heap[0];
        const last = heap.pop();
        if (heap.length > 0) {
            heap[0] = last;
            let i = 0;
            for (;;) {
                let s = i;
                const l = 2 * i + 1, r = 2 * i + 2;
                if (l < heap.length && heap[l] > heap[s]) s = l;
                if (r < heap.length && heap[r] > heap[s]) s = r;
                if (s === i) break;
                [heap[s], heap[i]] = [heap[i], heap[s]];
                i = s;
            }
        }
        return top;
    };
    let qSum = 0;
    let ans = Infinity;
    for (const [rate, q] of workers) {
        heapPush(q);
        qSum += q;
        if (heap.length > k) qSum -= heapPop();
        if (heap.length === k) ans = Math.min(ans, rate * qSum);
    }
    return ans;
};
